// src/search.ts
var index = data_default;
function searchIcons(query) {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return index.filter(
    (entry) => entry.terms.some((term) => term.includes(q))
  );
}
function getIcon(id) {
  return index.find((entry) => entry.id === id);
}
function getAllIcons() {
  return [...index];
}

// src/PosIcon.tsx
import { jsx } from "react/jsx-runtime";
function PosIcon({ id, size = 256, className, alt }) {
  const entry = getIcon(id);
  if (!entry) {
    console.warn(`PosIcon: Unknown icon id "${id}"`);
    return null;
  }
  return /* @__PURE__ */ jsx(
    "img",
    {
      src: entry.dataUri,
      width: size,
      height: size,
      alt: alt ?? entry.id,
      className,
      loading: "lazy"
    }
  );
}
export {
  PosIcon,
  getAllIcons,
  getIcon,
  searchIcons
};
